from smolagents import tool
from smolagents.llm import OpenAI

llm = OpenAI(model='gpt-4o-mini')

@tool
def extract_invoice(text: str, schema: str) -> str:
    '''Extract invoice data from text using provided schema'''
    prompt = f"""Extract invoice data from this text using the schema:
{schema}

Text: {text}

Return ONLY valid JSON:"""
    return llm.invoke(prompt)

