        vex.accuracy('invoice_number', source_text=invoice_text, threshold=0.95),
        vex.range_check('total', min=0, max=10000)
    ],
    risk_profile='medium'
)
def verified_extract(text: str) -> Invoice:
    result = agent.run(f"Extract invoice: {text}")
    return Invoice.model_validate_json(result)

@vex.verify(
    checks=[
        vex.schema(Invoice, strict=True),
        vex.completeness(['invoice_number', 'date', 'total']),
        vex.type_consistency(['quantity', 'unit_price'], float),
        vex.length_check('customer_name', min=2),
        vex.sandbox_code()  # Prevents unsafe execution
    ],
    fallback='retry',
    max_retries=3
)
def production_extract(text: str) -> Invoice:
    return Invoice.model_validate_json(agent.run(f"Extract: {text}"))

# Usage
result = production_extract(invoice_text)
